function clsStatus(status: string | undefined): string {
  return `status ${String(status || "waiting").toLowerCase().replace(/_/g, "-")}`;
}

function titleCase(value: string | undefined): string {
  return String(value || "waiting")
    .replace(/_/g, " ")
    .replace(/\b\w/g, (letter) => letter.toUpperCase());
}

function formatProductType(value: string | undefined): string {
  return titleCase(value)
    .replace(/\bDc\b/g, "DC")
    .replace(/\bAc\b/g, "AC")
    .replace(/\bUsb\b/g, "USB")
    .replace(/\bMcu\b/g, "MCU")
    .replace(/\bRf\b/g, "RF")
    .replace(/\bPcb\b/g, "PCB")
    .replace(/\bIo\b/g, "I/O");
}

function formatChatTime(date = new Date()): string {
  return date.toLocaleTimeString([], { hour: "numeric", minute: "2-digit" });
}

function isoNow(): string {
  return new Date().toISOString();
}

function taskRelativeTime(isoValue: string): string {
  const timestamp = Date.parse(isoValue);
  if (!Number.isFinite(timestamp)) return "";
  const diffMs = Math.max(0, Date.now() - timestamp);
  const minutes = Math.floor(diffMs / 60000);
  if (minutes < 1) return "now";
  if (minutes < 60) return `${minutes}m`;
  const hours = Math.floor(minutes / 60);
  if (hours < 24) return `${hours}h`;
  const days = Math.floor(hours / 24);
  if (days < 14) return `${days}d`;
  const weeks = Math.floor(days / 7);
  return `${weeks}w`;
}

function shortTaskTitle(value: string, fallback = "New task"): string {
  const text = value.trim().replace(/\s+/g, " ");
  if (!text) return fallback;
  return text.length > 38 ? `${text.slice(0, 35)}...` : text;
}

function createCopilotTask(title: string, source: CopilotTaskSource = "manual", messages: ChatMessage[] = []): CopilotTask {
  const now = isoNow();
  return {
    id: `copilot-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`,
    title: shortTaskTitle(title, "Start Project"),
    createdAt: now,
    updatedAt: now,
    messages,
    source,
    status: "active",
  };
}

function sanitizeCopilotTasks(raw: unknown): CopilotTask[] {
  if (!Array.isArray(raw)) return [];
  return raw.flatMap((item): CopilotTask[] => {
    if (!item || typeof item !== "object") return [];
    const record = item as AnyRecord;
    const messages = Array.isArray(record.messages)
      ? record.messages.flatMap((message: AnyRecord): ChatMessage[] => {
          if (!message || typeof message !== "object") return [];
          const from = String(message.from || "assistant") === "user" ? "user" : "assistant";
          const body = String(message.body || "").trim();
          if (!body) return [];
          return [{ from, time: String(message.time || formatChatTime()), body }];
        })
      : [];
    const now = isoNow();
    const source = ["project", "manual", "requirement"].includes(String(record.source)) ? String(record.source) as CopilotTaskSource : "manual";
    const status = ["active", "done", "error"].includes(String(record.status)) ? String(record.status) as CopilotTaskStatus : "active";
    return [{
      id: String(record.id || `copilot-${Math.random().toString(36).slice(2, 8)}`),
      title: shortTaskTitle(String(record.title || "New task"), "New task"),
      createdAt: String(record.createdAt || now),
      updatedAt: String(record.updatedAt || record.createdAt || now),
      messages,
      source,
      status,
    }];
  });
}

type ChatMessage = { from: string; time: string; body: string };
type CopilotTaskStatus = "active" | "done" | "error";
type CopilotTaskSource = "project" | "manual" | "requirement";
type CopilotView = "list" | "chat";
type CopilotTask = {
  id: string;
  title: string;
  createdAt: string;
  updatedAt: string;
  messages: ChatMessage[];
  source: CopilotTaskSource;
  status: CopilotTaskStatus;
};

