type EdaTabDefinition = {
  id: string;
  label: string;
  phase: "Design" | "Test";
  step?: WorkflowStep;
};

function canonicalWorkflowTabId(step: WorkflowStep): string {
  const aliases: Record<string, string> = {
    specifications: "requirements",
    requirement: "requirements",
    requirements: "requirements",
    parts: "bom",
    component_inventory: "bom",
    component_selection: "bom",
    drc_review: "review",
    compliance_review: "review",
    design_review: "review",
    embedded_coding_download: "codes",
    closed_loop_tuning: "tuning",
    efficiency_logging: "measurement_data",
  };
  return aliases[step.id] || step.id;
}

function workflowTabsForPhase(plan: WorkflowPlan, phase: ProjectPhase): EdaTabDefinition[] {
  const wantedPhase = phase === "design" ? "Design" : "Test";
  const priority = phase === "design" ? ["requirements", "analysis", "simulation", "bom", "pcb", "review"] : [];
  const byId = new Map<string, EdaTabDefinition>();
  plan.workflowSteps
    .filter((step) => step.phase === wantedPhase)
    .forEach((step) => {
      const id = canonicalWorkflowTabId(step);
      const existing = byId.get(id);
      const existingIsAlias = existing?.step ? canonicalWorkflowTabId(existing.step) !== existing.step.id : false;
      const nextIsExact = id === step.id;
      if (!existing || (existingIsAlias && nextIsExact)) {
        byId.set(id, { id, label: step.title, phase: wantedPhase, step });
      }
    });
  const tabs = Array.from(byId.values());
  if (!priority.length) return tabs;
  return tabs.sort((a, b) => {
    const aIndex = priority.indexOf(a.id);
    const bIndex = priority.indexOf(b.id);
    if (aIndex === -1 && bIndex === -1) return 0;
    return (aIndex === -1 ? Number.MAX_SAFE_INTEGER : aIndex) - (bIndex === -1 ? Number.MAX_SAFE_INTEGER : bIndex);
  });
}

function allWorkflowTabs(plan: WorkflowPlan): EdaTabDefinition[] {
  return [...workflowTabsForPhase(plan, "design"), ...workflowTabsForPhase(plan, "test")];
}

function workflowStepForTab(plan: WorkflowPlan, tab: string): WorkflowStep | undefined {
  return allWorkflowTabs(plan).find((item) => item.id === tab)?.step;
}

function phaseForTab(plan: WorkflowPlan, tab: string): "Design" | "Test" | undefined {
  return allWorkflowTabs(plan).find((item) => item.id === tab)?.phase;
}

function firstTabForPhase(plan: WorkflowPlan, phase: ProjectPhase): string {
  return workflowTabsForPhase(plan, phase)[0]?.id || (phase === "design" ? "requirements" : "test_report");
}

