function isDesignTab(tab: string, plan?: WorkflowPlan): boolean {
  if (plan) return phaseForTab(plan, tab) === "Design";
  return (DESIGN_TABS as readonly string[]).includes(tab);
}

function isTestTab(tab: string, plan?: WorkflowPlan): tab is TestWorkspaceTab {
  if (plan) return phaseForTab(plan, tab) === "Test";
  return (LEGACY_TEST_TABS as readonly string[]).includes(tab);
}

function sanitizeTestFeedbackItem(value: unknown): TestFeedbackItem | null {
  if (!value || typeof value !== "object") return null;
  const record = value as AnyRecord;
  const tab = isTestTab(String(record.tab)) ? String(record.tab) as TestWorkspaceTab : "report";
  const severity = ["note", "minor", "major", "critical"].includes(String(record.severity))
    ? String(record.severity) as TestFeedbackSeverity
    : "note";
  const body = String(record.body || "").trim();
  if (!body) return null;
  return {
    id: String(record.id || `feedback-${Date.now()}`),
    tab,
    severity,
    body,
    suggestedAction: String(record.suggestedAction || "").trim(),
    createdAt: String(record.createdAt || isoNow()),
  };
}

function sanitizePrototypeGate(value: unknown): PrototypeGateState {
  if (!value || typeof value !== "object") return DEFAULT_PROTOTYPE_GATE;
  const record = value as AnyRecord;
  const phase: ProjectPhase = record.phase === "test" ? "test" : "design";
  const feedbackItems = Array.isArray(record.feedbackItems)
    ? record.feedbackItems.map(sanitizeTestFeedbackItem).filter(Boolean) as TestFeedbackItem[]
    : [];
  return {
    phase,
    designLocked: phase === "test" ? Boolean(record.designLocked ?? true) : Boolean(record.designLocked),
    enteredTestAt: typeof record.enteredTestAt === "string" ? record.enteredTestAt : undefined,
    feedbackItems,
  };
}

