function edaStatusFromStageStatus(status: string, options?: { verified?: boolean; review?: boolean }): EdaStatus {
  if (["blocked", "error", "failed"].includes(status)) return "failed";
  if (status === "running" || status === "active") return "running";
  if (status === "complete") {
    if (options?.review) return "needs_review";
    if (options?.verified) return "verified";
    return "completed";
  }
  if (status === "partial") return "needs_review";
  return "pending";
}

