function downstreamModulesForPlan(plan: WorkflowPlan, approved: boolean, outdated = false): WorkflowModule[] {
  const status: EdaStatus = approved ? (outdated ? "outdated" : "ready") : "pending";
  return plan.workflowSteps.map((step) => ({
    id: canonicalWorkflowTabId(step),
    name: step.title,
    phase: step.phase === "Test" ? "test" : "design",
    description: step.description,
    outputArtifacts: step.sourceStageIds,
    status: canonicalWorkflowTabId(step) === "requirements"
      ? (approved ? "verified" : "running")
      : step.phase === "Test" && !approved
        ? "locked"
        : status,
  }));
}

function createRequirementPlan(plan: WorkflowPlan): RequirementPlan {
  const domainId = plan.classification.primaryDomain;
  const base = REQUIREMENT_PLAN_LIBRARY[domainId] || REQUIREMENT_PLAN_LIBRARY.general_pcb;
  const downstreamModules = downstreamModulesForPlan(plan, false);
  return {
    id: `${domainId}-${base.projectTitle.toLowerCase().replace(/[^a-z0-9]+/g, "-")}`,
    domainId,
    projectTitle: base.projectTitle,
    projectRequest: base.projectRequest,
    productType: base.productType,
    summary: base.summary,
    confidenceLabel: plan.classification.confidence,
    classificationSource: plan.classification.source,
    status: "draft",
    sections: base.sections.map((section) => ({ ...section, status: "draft" as RequirementSectionStatus })),
    keyMetrics: requirementMetricsForDomain(domainId),
    downstreamModules,
  };
}

function mergeRequirementPlan(basePlan: RequirementPlan, edit?: RequirementPlanEditState): RequirementPlan {
  const status = edit?.status || basePlan.status;
  const approved = status === "approved";
  const changedAfterApproval = Boolean(edit?.changedAfterApproval);
  return {
    ...basePlan,
    status,
    lastUpdated: edit?.lastUpdated,
    changedAfterApproval,
    downstreamModules: basePlan.downstreamModules.map((moduleItem) => ({
      ...moduleItem,
      status: moduleItem.id === "requirements"
        ? (approved ? "verified" : "running")
        : moduleItem.phase === "test" && !approved
          ? "locked"
          : approved || changedAfterApproval
            ? (changedAfterApproval ? "outdated" : "ready")
            : "pending",
    })),
    sections: basePlan.sections.map((section) => ({
      ...section,
      content: edit?.sectionContent?.[section.id] || section.content,
      status: approved && !changedAfterApproval
        ? "approved"
        : edit?.sectionStatus?.[section.id] || section.status,
      revisionHistory: edit?.revisionHistory?.[section.id] || section.revisionHistory || [],
    })),
  };
}

