function localizedRequirementPlanSummary(plan: RequirementPlan, language: UiLanguage): string {
  return language === "zh" ? REQUIREMENT_PLAN_ZH[plan.domainId]?.summary || plan.summary : plan.summary;
}

function localizedRequirementProductType(plan: RequirementPlan, language: UiLanguage): string {
  return language === "zh" ? REQUIREMENT_PLAN_ZH[plan.domainId]?.productType || plan.productType : plan.productType;
}

function localizedRequirementSection(section: RequirementPlanSection, domainId: ProjectDomain, language: UiLanguage) {
  return language === "zh" ? REQUIREMENT_PLAN_ZH[domainId]?.sections[section.id] : undefined;
}

function localizedRequirementSectionContent(section: RequirementPlanSection, domainId: ProjectDomain, language: UiLanguage): string[] {
  if (language !== "zh") return section.content;
  const localized = localizedRequirementSection(section, domainId, language);
  const revisionItems = section.content
    .filter((item) => item.startsWith("Revision:"))
    .map((item) => item.replace(/^Revision:\s*/, "ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¤ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¿ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â®ÃƒÆ’Ã†â€™Ãƒâ€ Ã¢â‚¬â„¢ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¨ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â®ÃƒÆ’Ã†â€™ÃƒÂ¢Ã¢â€šÂ¬Ã…Â¡ÃƒÆ’Ã¢â‚¬Å¡Ãƒâ€šÃ‚Â¢:"));
  return [...(localized?.content || section.content), ...revisionItems];
}

function localizedRequirementMetric(metric: RequirementMetric, language: UiLanguage) {
  return {
    label: language === "zh" ? metric.labelZh : metric.label,
    value: language === "zh" ? metric.valueZh : metric.value,
  };
}

