function edaRefFromPart(part: AnyRecord, index: number): string {
  const role = String(part.role || part.category || "").toLowerCase();
  if (role.includes("mosfet") || role.includes("fet") || role.includes("switch")) return index % 2 === 0 ? "Q1" : "Q2";
  if (role.includes("inductor")) return "L1";
  if (role.includes("capacitor") || role.includes("cap")) return `C${index + 1}`;
  if (role.includes("controller") || role.includes("mcu") || role.includes("ic")) return `U${index + 1}`;
  if (role.includes("resistor")) return `R${index + 1}`;
  return `U${index + 1}`;
}

type BomDecisionStatus = "draft" | "needs_review" | "approved" | "locked" | "replaced" | "missing_evidence" | "supply_risk" | "outdated";
type BomFilter = "all" | "needs_review" | "supply_risk" | "missing_evidence" | "approved" | "locked";
type BomColumnSet = "engineering" | "procurement" | "risk";
type BomGroupBy = "none" | "category" | "manufacturer" | "status";

type BomAlternative = {
  mpn: string;
  compatibility: string;
  keyDifference: string;
  risk: string;
  cost: string;
  stock: string;
  recommendation: string;
};

type BomDecisionItem = {
  id: string;
  ref: string;
  function: string;
  category: string;
  selectedMpn: string;
  keySpecs: string;
  ratingMargin: string;
  qty: number;
  manufacturer: string;
  packageName: string;
  unitCost: string;
  stock: string;
  lifecycle: string;
  risk: string;
  status: BomDecisionStatus;
  evidence: string;
  rationale: string[];
  requirementMapping: string[];
  datasheetParams: string[];
  deratingChecks: string[];
  alternatives: BomAlternative[];
  supplyRisk: string[];
  layoutNotes: string[];
  flags?: Array<"supply_risk" | "missing_evidence" | "critical" | "layout_sensitive">;
};

function alt(mpn: string, compatibility: string, keyDifference: string, risk: string, cost: string, stock: string, recommendation: string): BomAlternative {
  return { mpn, compatibility, keyDifference, risk, cost, stock, recommendation };
}

