function bomModuleGenerated(state: AnyRecord, plan: WorkflowPlan): boolean {
  if (state.partsCatalog?.available) return true;
  if (state.workflowStatus === "complete") return true;
  const stages = combinedStagePayloads(state);
  const sourceIds = [
    "select_parts",
    "parts",
    "component_inventory",
    "rf_ic_selection",
    "antenna_selection",
    "matching_network",
    "mcu_selection",
    "interface_selection",
    "op_amp_selection",
    "adc_selection",
    "processor_or_fpga_selection",
    "memory_interface",
    "power_integrity",
  ];
  return sourceStatus(stages, sourceIds) !== "waiting";
}

function buildBomDecisionRows(state: AnyRecord, plan: WorkflowPlan): BomDecisionItem[] {
  if (!bomModuleGenerated(state, plan)) return [];
  const domain = plan.classification.primaryDomain;
  const baseRows = BOM_DECISION_LIBRARY[domain] || BOM_DECISION_LIBRARY.general_pcb;
  const backendParts = state.partsCatalog?.items || [];
  if (!backendParts.length || domain !== "power_electronics") return baseRows.map((row) => ({ ...row, alternatives: [...row.alternatives] }));
  const backendByRole = new Map<string, AnyRecord>();
  backendParts.forEach((part: AnyRecord) => {
    backendByRole.set(String(part.role || "").toLowerCase(), part);
  });
  return baseRows.map((row, index) => {
    const role = row.function.toLowerCase();
    const backend = [...backendByRole.entries()].find(([key]) => role.includes(key) || key.includes(role.split(" ")[0]))?.[1] || backendParts[index];
    if (!backend) return { ...row, alternatives: [...row.alternatives] };
    return {
      ...row,
      selectedMpn: backend.mpn || row.selectedMpn,
      manufacturer: backend.manufacturer || row.manufacturer,
      qty: Number(backend.quantity || row.qty),
      unitCost: typeof backend.unitPriceUsd === "number" ? `$${backend.unitPriceUsd.toFixed(2)}` : row.unitCost,
      keySpecs: Array.isArray(backend.keyParams) && backend.keyParams.length ? backend.keyParams.slice(0, 3).join("; ") : row.keySpecs,
      evidence: row.evidence.includes("Demo") ? "Demo supplier data" : row.evidence,
      alternatives: [...row.alternatives],
    };
  });
}

