function EngineeringProjectHeader({
  state,
  actions,
  plan,
  requirementApproved,
  onOpenInvestor,
  darkTheme,
  onSetDarkTheme,
}: {
  state: AnyRecord;
  actions: AnyRecord;
  plan: WorkflowPlan;
  requirementApproved: boolean;
  onOpenInvestor: () => void;
  darkTheme: boolean;
  onSetDarkTheme: (enabled: boolean) => void;
}) {
  const spec = state.spec || state.rawState?.spec || {};
  const profile = demoProfileForPlan(plan);
  const statusStages = state.demoMode === "profile_fake" ? (state.activeDemoStages || []) : (state.stages || []);
  const completed = statusStages.filter((stage: AnyRecord) => stage.status === "complete").length;
  const total = statusStages.length || plan.workflowSteps.length;
  const status = state.workflowStatus === "complete" ? "Needs Review" : state.running ? "Running" : "Ready";
  const projectName = plan.classification.primaryDomain === "power_electronics"
    ? String(spec.name || profile.projectName).replace(/^AutoEE\s+/i, "").replace(/\s+Demo$/i, "")
    : profile.projectName;
  return (
    <header className="projectHeader">
      <div>
        <span className="projectKicker">Project</span>
        <h1>{projectName}</h1>
        <div className="projectMeta">
          <span>{domainName(plan.classification.primaryDomain)}</span>
          <span>{profile.circuitName}</span>
          <span>{completed} / {total} modules complete</span>
        </div>
      </div>
      <div className="projectStatusBlock">
        <span className={`projectStatus ${status.toLowerCase().replace(/\s+/g, "-")}`}>{status}</span>
        <div className="projectActions">
          <button className="primary" onClick={() => actions.runDemo(demoRunPayload(plan))} disabled={state.running}>{state.running ? "Running..." : "Run Demo"}</button>
          <div className="themeSwitch" aria-label="Engineering Console theme">
            <button className={!darkTheme ? "active" : ""} onClick={() => onSetDarkTheme(false)}>Day</button>
            <button className={darkTheme ? "active" : ""} onClick={() => onSetDarkTheme(true)}>Night</button>
          </div>
        </div>
      </div>
    </header>
  );
}

function LanguageSwitch({
  language,
  onSetLanguage,
}: {
  language: UiLanguage;
  onSetLanguage: (language: UiLanguage) => void;
}) {
  return (
    <div className="languageSwitch" aria-label="Language">
      <button
        type="button"
        className={language === "zh" ? "active" : ""}
        onClick={() => onSetLanguage("zh")}
        aria-label="Switch to Chinese"
        aria-pressed={language === "zh"}
        title="Switch to Chinese"
      >
        {"\u4e2d"}
      </button>
      <button
        type="button"
        className={language === "en" ? "active" : ""}
        onClick={() => onSetLanguage("en")}
        aria-label="Switch to English"
        aria-pressed={language === "en"}
        title="Switch to English"
      >
        EN
      </button>
    </div>
  );
}
function EdaTopBar({
  state,
  actions,
  plan,
  activeProject,
  onOpenInvestor,
  onOpenProjects,
  onImportDemo,
  darkTheme,
  onSetDarkTheme,
  canResetDemo,
  onResetDemo,
  requirementApproved,
  prototypeGate,
  onEnterTestPhase,
  onUnlockDesign,
  language,
  onSetLanguage,
}: {
  state: AnyRecord;
  actions: AnyRecord;
  plan: WorkflowPlan;
  activeProject?: AutoEEProject | null;
  onOpenInvestor: () => void;
  onOpenProjects: () => void;
  onImportDemo: () => void;
  darkTheme: boolean;
  onSetDarkTheme: (enabled: boolean) => void;
  canResetDemo: boolean;
  onResetDemo: () => void;
  requirementApproved: boolean;
  prototypeGate: PrototypeGateState;
  onEnterTestPhase: () => void;
  onUnlockDesign: () => void;
  language: UiLanguage;
  onSetLanguage: (language: UiLanguage) => void;
}) {
  void onOpenInvestor;
  const profile = demoProfileForPlan(plan);
  const projectName = activeProject?.title || projectNameForPlan(state, plan);
  const reviewStatus = state.workflowStatus === "complete" ? "Ready for Review" : state.running ? "Running" : "Needs Review";
  const reviewStatusLabel = state.workflowStatus === "complete"
    ? uiText(language, "Ready for Review", "\u5f85\u8bc4\u5ba1")
    : state.running
      ? uiText(language, "Running", "\u8fd0\u884c\u4e2d")
      : uiText(language, "Needs Review", "\u9700\u8981\u8bc4\u5ba1");
  const progress = workflowProgressPercent(state, plan);
  const progressRunning = Boolean(state.running && state.workflowStatus !== "complete");
  const progressComplete = state.workflowStatus === "complete";
  const inTestPhase = prototypeGate.phase === "test";
  const phaseLabel = inTestPhase
    ? uiText(language, "Unlock Design", "\u89e3\u9501\u8bbe\u8ba1")
    : requirementApproved
      ? uiText(language, "Enter Test", "\u8fdb\u5165\u6d4b\u8bd5")
      : uiText(language, "Approve Plan", "\u5148\u6279\u51c6\u8ba1\u5212");
  const runLabel = state.running ? uiText(language, "Running...", "\u8fd0\u884c\u4e2d...") : uiText(language, "Run Demo", "\u8fd0\u884c\u6f14\u793a");
  return (
    <header className="edaTopBar">
      <div className="edaTopProject">
        <strong>{projectName}</strong>
        <span>{domainDisplayName(plan.classification.primaryDomain, language)} / {profile.circuitName}</span>
      </div>
      <div className="edaTopStatus">
        <span className="edaAgentBadge">AutoEE Agent <b>Live</b></span>
        <span className={`edaReviewBadge ${reviewStatus.toLowerCase().replace(/\s+/g, "-")} ${progressRunning ? "running-progress" : ""} ${progressComplete ? "complete-progress" : ""}`}>
          <i><b style={{ width: `${progress}%` }} /></i>
          <em>{progress}%</em>
          <span>{reviewStatusLabel}</span>
        </span>
      </div>
      <div className="edaTopActions">
        <button type="button" onClick={onOpenProjects}>{uiText(language, "My Projects", "\u6211\u7684\u9879\u76ee")}</button>
        <button type="button" onClick={onImportDemo} title={uiText(language, "Add current demo to My Projects", "\u628a\u5f53\u524d Demo \u6dfb\u52a0\u5230\u6211\u7684\u9879\u76ee")}>
          {uiText(language, "Add Demo", "\u6dfb\u52a0 Demo")}
        </button>
        <button
          type="button"
          className={inTestPhase ? "" : "primary"}
          onClick={inTestPhase ? onUnlockDesign : onEnterTestPhase}
          disabled={state.running || !requirementApproved}
        >
          {phaseLabel}
        </button>
        <button className="primary" onClick={() => actions.runDemo(demoRunPayload(plan))} disabled={state.running || !requirementApproved}>
          {runLabel}
        </button>
        <button onClick={onResetDemo} disabled={!canResetDemo}>{uiText(language, "Reset", "\u91cd\u7f6e")}</button>
        <LanguageSwitch language={language} onSetLanguage={onSetLanguage} />
        <div className="themeIconSwitch" aria-label="Engineering Console theme">
          <button
            type="button"
            className={!darkTheme ? "active" : ""}
            onClick={() => onSetDarkTheme(false)}
            aria-label="Day mode"
            aria-pressed={!darkTheme}
            title="Day mode"
          >
            <svg viewBox="0 0 24 24" aria-hidden="true">
              <circle cx="12" cy="12" r="4" />
              <path d="M12 2.75V5.2M12 18.8v2.45M5.45 5.45l1.73 1.73M16.82 16.82l1.73 1.73M2.75 12H5.2M18.8 12h2.45M5.45 18.55l1.73-1.73M16.82 7.18l1.73-1.73" />
            </svg>
          </button>
          <button
            type="button"
            className={darkTheme ? "active" : ""}
            onClick={() => onSetDarkTheme(true)}
            aria-label="Night mode"
            aria-pressed={darkTheme}
            title="Night mode"
          >
            <svg viewBox="0 0 24 24" aria-hidden="true">
              <path d="M20.2 14.4A7.6 7.6 0 0 1 9.6 3.8 8.2 8.2 0 1 0 20.2 14.4Z" />
            </svg>
          </button>
        </div>
      </div>
    </header>
  );
}

