function revisionFeedbackMarkdown(plan: WorkflowPlan, state: AnyRecord, gate: PrototypeGateState): string {
  const projectName = projectNameForPlan(state, plan);
  const feedback = gate.feedbackItems.length
    ? gate.feedbackItems
    : [{
        id: "default-revision-action",
        tab: "report" as TestWorkspaceTab,
        severity: "major" as TestFeedbackSeverity,
        body: "Review thermal margin, add more test access, and rerun real lab evidence before Rev B signoff.",
        suggestedAction: "Update PCB thermal copper, test pads, and validation checklist.",
        createdAt: isoNow(),
      }];
  const lines = [
    `# ${projectName} Revision Feedback`,
    "",
    `- Project phase: ${gate.phase}`,
    `- Design locked: ${gate.designLocked ? "yes" : "no"}`,
    `- Entered test phase: ${gate.enteredTestAt || "not recorded"}`,
    `- Domain: ${domainName(plan.classification.primaryDomain)}`,
    "",
    "## Feedback Items",
    "",
    ...feedback.flatMap((item, index) => [
      `### ${index + 1}. ${testTabTitle(item.tab, "en", plan)} / ${item.severity}`,
      "",
      `- Time: ${item.createdAt}`,
      `- Issue: ${item.body}`,
      `- Suggested next design change: ${item.suggestedAction || "TBD"}`,
      "",
    ]),
    "## Next Revision Guidance",
    "",
    "- Feed these findings back into Requirement, BOM, PCB, and Verification before starting the next hardware revision.",
    "- Treat this file as Rev A test feedback, not final production signoff.",
    "",
  ];
  return lines.join("\n");
}

